#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-06-22

# strict-mode: opt-out a statusline must NEVER hard-fail (blank bar); every step fails open to empty
#
# ork-session-color.sh — give your Claude Code statusline a LIVE per-session
# color dot, recovered from the transcript's last `agent-color` record (the same
# record ork's session-identity hook and /color write).
#
# Why this exists: CC's statusline JSON has NO color field, and hooks cannot set
# the live bar color. But the statusline JSON DOES include `transcript_path`, and
# we already write the session color there — so the statusline can read it back
# and paint itself. The dot tracks the session color from the first prompt (hash
# color), upgrading to the work-category color once the haiku titler lands.
#
# Wire it in ~/.claude/settings.json:
#   Standalone (dot + session name):
#     "statusLine": { "type": "command", "command": "/ABS/PATH/ork-session-color.sh" }
#   Wrap your existing statusline (keep claude-hud, just prepend the dot):
#     "command": "/ABS/PATH/ork-session-color.sh -- claude-hud"
#     (replace `claude-hud` with your current statusLine command + its args)
#
# Style — set ORK_COLOR_STYLE in your env (default `dot`):
#   dot    — a small ● in the session color (foreground)
#   block  — a solid BACKGROUND swatch in the session color
# (Note: this is the only way to get a live per-session bar color — CC's native
#  /color in-memory setter is interactive-only and unreachable from a hook/API.)
#
# Portable to macOS + Linux (uses `grep | tail`, not GNU `tac`).

input="$(cat)"

# --- read a top-level string field from the CC statusline JSON ---------------
json_get() { # $1 = jq path, $2 = key name (sed fallback)
  if command -v jq >/dev/null 2>&1; then
    # silent: fail-open — bad/empty JSON yields no field, statusline still renders
    jq -r "$1 // empty" <<<"$input" 2>/dev/null || true
  else
    sed -n "s/.*\"$2\"[[:space:]]*:[[:space:]]*\"\\([^\"]*\\)\".*/\\1/p" <<<"$input" | head -1
  fi
}

# --- recover the session color from the transcript ---------------------------
transcript="$(json_get '.transcript_path' transcript_path)"
color=""
if [ -n "$transcript" ] && [ -f "$transcript" ]; then
  # Last agent-color record wins (matches CC's /resume picker reader). grep all
  # such lines (they are few) and take the last — portable, no `tac`/`tail -r`.
  # silent: fail-open — no record / unreadable transcript just means no color dot
  line="$(grep '"type":"agent-color"' "$transcript" 2>/dev/null | tail -1 || true)"
  if [ -n "$line" ]; then
    if command -v jq >/dev/null 2>&1; then
      # silent: fail-open — malformed record yields no color, dot is omitted
      color="$(jq -r '.agentColor // empty' <<<"$line" 2>/dev/null || true)"
    else
      color="$(sed -n 's/.*"agentColor"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p' <<<"$line")"
    fi
  fi
fi

# --- map the color name → a 256-color number (tuned to match the title emoji) -
cnum=""
case "$color" in
  red)    cnum=196 ;;
  blue)   cnum=39  ;;
  green)  cnum=46  ;;
  yellow) cnum=226 ;;
  purple) cnum=141 ;;
  orange) cnum=208 ;;
  pink)   cnum=205 ;;
  cyan)   cnum=51  ;;
esac

# Render style — set ORK_COLOR_STYLE in your env:
#   dot   (default) — a small ● in the session color (foreground)
#   block          — a solid background swatch in the session color
esc=$'\033'
reset="${esc}[0m"
dot=""
if [ -n "$cnum" ]; then
  case "${ORK_COLOR_STYLE:-dot}" in
    block) dot="${esc}[48;5;${cnum}m  ${reset} " ;; # bg swatch (two spaces)
    *)     dot="${esc}[38;5;${cnum}m●${reset} " ;;  # fg dot
  esac
fi

# --- render ------------------------------------------------------------------
if [ "${1:-}" = "--" ]; then
  shift
  # Wrap mode: feed the SAME JSON to the downstream statusline, prepend the dot.
  # silent: fail-open — if the wrapped statusline errors, still show the dot
  rest="$(printf '%s' "$input" | "$@" 2>/dev/null || true)"
  printf '%s%s' "$dot" "$rest"
else
  # Standalone: dot + session name (or a short session id).
  name="$(json_get '.session_name' session_name)"
  [ -z "$name" ] && name="$(json_get '.session_id' session_id | cut -c1-8)"
  printf '%s%s' "$dot" "$name"
fi
